/**
 * Tests for `mesh-policy-compile.ts` + `mesh-policy-edge-compiled.ts`.
 *
 * Five groups:
 *   1. compile is pure and deterministic
 *   2. round-trip exact deep-equality
 *   3. behavioral parity with raw-config `wrapWithMeshPolicy`
 *   4. manifest inspection
 *   5. version validation
 *
 * Node-free runtime requirement is asserted by a source-file scan in
 * Group 5.
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import {
  wrapWithMeshPolicy,
  type InnerFetch,
  type MeshPolicyConfig,
} from '../mesh-policy-edge';
import {
  compileMeshPolicy,
  fingerprintMeshPolicyBundle,
  inspectCompiledBundle,
  loadMeshPolicyFromBundle,
  MESH_POLICY_BW_MAGIC,
  MESH_POLICY_BW_KIND,
  MESH_POLICY_BW_VERSION,
  MESH_POLICY_MANIFEST_FORMAT,
} from '../mesh-policy-compile';
import {
  inspectCompiledBundle as inspectCompiledBundleAlt,
  wrapWithMeshPolicyCompiled,
} from '../mesh-policy-edge-compiled';

// ─── Fixtures ───────────────────────────────────────────────────────

const emptyPolicy: MeshPolicyConfig = { ports: [] };

const singlePortPolicy: MeshPolicyConfig = {
  ports: [{ path: '/api', methods: ['GET', 'POST'] }],
};

const multiPortWithOverlays: MeshPolicyConfig = {
  ports: [
    { path: '/api', methods: ['GET', 'POST'] },
    { path: '/health' },
    { path: '/internal', methods: ['GET'] },
  ],
  overlays: [
    { pathPrefix: '/api/admin', reason: 'restricted' },
    { pathPrefix: '/internal/debug', reason: 'debug disabled' },
  ],
};

const withHoneypitPolicy: MeshPolicyConfig = {
  ports: [{ path: '/api', methods: ['GET'] }],
  overlays: [
    { pathPrefix: '/api/trap', reason: 'honeypot', honeypit: true },
  ],
  honeypit: { capacity: 10, drainSlots: 2 },
};

const withAuthPolicy: MeshPolicyConfig = {
  ports: [{ path: '/api', methods: ['GET', 'POST'] }],
  requireAuthHeaderPresent: true,
};

const withAdoptionModePolicy: MeshPolicyConfig = {
  ports: [{ path: '/api', methods: ['GET'] }],
  overlays: [{ pathPrefix: '/api/blocked', reason: 'shadow-mode' }],
  mode: 'audit',
};

const allFixtures: readonly {
  readonly name: string;
  readonly policy: MeshPolicyConfig;
}[] = [
  { name: 'empty', policy: emptyPolicy },
  { name: 'single-port', policy: singlePortPolicy },
  { name: 'multi-port-overlays', policy: multiPortWithOverlays },
  { name: 'with-honeypit', policy: withHoneypitPolicy },
  { name: 'with-auth', policy: withAuthPolicy },
  { name: 'with-adoption-mode', policy: withAdoptionModePolicy },
];

// ─── Helpers ────────────────────────────────────────────────────────

const okInner: InnerFetch = () =>
  new Response('ok', {
    status: 200,
    headers: { 'content-type': 'text/plain' },
  });

const emptyEnv = {} as Record<string, unknown>;
const emptyCtx: unknown = undefined;

function deepEquals(a: unknown, b: unknown): boolean {
  if (Object.is(a, b)) return true;
  if (a === null || b === null) return a === b;
  if (typeof a !== 'object' || typeof b !== 'object') return false;
  if (Array.isArray(a) !== Array.isArray(b)) return false;
  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) {
      if (!deepEquals(a[i], b[i])) return false;
    }
    return true;
  }
  const aRec = a as Record<string, unknown>;
  const bRec = b as Record<string, unknown>;
  const aKeys = Object.keys(aRec).sort();
  const bKeys = Object.keys(bRec).sort();
  if (aKeys.length !== bKeys.length) return false;
  for (let i = 0; i < aKeys.length; i++) {
    if (aKeys[i] !== bKeys[i]) return false;
  }
  for (const k of aKeys) {
    if (!deepEquals(aRec[k], bRec[k])) return false;
  }
  return true;
}

function bytesEqual(a: Uint8Array, b: Uint8Array): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return false;
  }
  return true;
}

interface ResponseSnapshot {
  readonly status: number;
  readonly body: string;
  readonly allow: string | null;
  readonly wwwAuth: string | null;
  readonly contentType: string | null;
}

async function snapshot(res: Response): Promise<ResponseSnapshot> {
  const body = await res.text();
  return {
    status: res.status,
    body,
    allow: res.headers.get('Allow'),
    wwwAuth: res.headers.get('WWW-Authenticate'),
    contentType: res.headers.get('content-type'),
  };
}

async function runBoth(
  policy: MeshPolicyConfig,
  req: Request,
): Promise<{ readonly raw: ResponseSnapshot; readonly compiled: ResponseSnapshot }> {
  const rawWrap = wrapWithMeshPolicy(okInner, policy);
  const bundle = compileMeshPolicy(policy);
  const compiledWrap = wrapWithMeshPolicyCompiled(okInner, bundle.bwBytes);
  // Clone the request for each side because fetch Request bodies are
  // one-shot streams.
  const rawReq = req.clone();
  const compiledReq = req.clone();
  const rawRes = await rawWrap(rawReq, emptyEnv, emptyCtx);
  const compiledRes = await compiledWrap(compiledReq, emptyEnv, emptyCtx);
  return { raw: await snapshot(rawRes), compiled: await snapshot(compiledRes) };
}

function assertSameResponse(
  raw: ResponseSnapshot,
  compiled: ResponseSnapshot,
): void {
  expect(compiled.status).toBe(raw.status);
  expect(compiled.body).toBe(raw.body);
  expect(compiled.allow).toBe(raw.allow);
  expect(compiled.wwwAuth).toBe(raw.wwwAuth);
  expect(compiled.contentType).toBe(raw.contentType);
}

describe('mesh-policy-compile', () => {
  // ─── Group 1: compile is pure and deterministic ────────────────────
  describe('compile determinism and manifest integrity', () => {
    it('returns byte-identical bundles for identical inputs with identical timestamps', () => {
      const a = compileMeshPolicy(multiPortWithOverlays, {
        timestamp: '2026-04-19T12:00:00.000Z',
      });
      const b = compileMeshPolicy(multiPortWithOverlays, {
        timestamp: '2026-04-19T12:00:00.000Z',
      });
      expect(bytesEqual(a.bwBytes, b.bwBytes)).toBe(true);
    });

    it('default timestamp yields deterministic output across calls', () => {
      const a = compileMeshPolicy(singlePortPolicy);
      const b = compileMeshPolicy(singlePortPolicy);
      expect(bytesEqual(a.bwBytes, b.bwBytes)).toBe(true);
    });

    it('output starts with BZRO magic bytes', () => {
      for (const fx of allFixtures) {
        const { bwBytes } = compileMeshPolicy(fx.policy);
        for (let i = 0; i < 4; i++) {
          expect(bwBytes[i]).toBe(MESH_POLICY_BW_MAGIC[i]);
        }
      }
    });

    it('writes version = 1 and kind = 2 (mesh-policy)', () => {
      const { bwBytes } = compileMeshPolicy(singlePortPolicy);
      expect(bwBytes[4]).toBe(MESH_POLICY_BW_VERSION);
      expect(bwBytes[5]).toBe(MESH_POLICY_BW_KIND);
    });

    it('manifest.format is "mesh-policy-v1" for every fixture', () => {
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        expect(manifest.format).toBe(MESH_POLICY_MANIFEST_FORMAT);
      }
    });

    it('manifest.portCount matches config.ports.length', () => {
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        expect(manifest.portCount).toBe(fx.policy.ports.length);
      }
    });

    it('manifest.overlayCount matches config.overlays.length (or 0)', () => {
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        expect(manifest.overlayCount).toBe(fx.policy.overlays?.length ?? 0);
      }
    });

    it('manifest.authFlag reflects requireAuthHeaderPresent ?? requireAuth', () => {
      expect(compileMeshPolicy(withAuthPolicy).manifest.authFlag).toBe(true);
      expect(compileMeshPolicy(singlePortPolicy).manifest.authFlag).toBe(false);
      const legacy: MeshPolicyConfig = {
        ports: [{ path: '/x' }],
        requireAuth: true,
      };
      expect(compileMeshPolicy(legacy).manifest.authFlag).toBe(true);
    });

    it('manifest.modeCode encodes adoption mode (0 enforce, 1 audit, 2 shadow)', () => {
      expect(compileMeshPolicy(singlePortPolicy).manifest.modeCode).toBe(0);
      expect(compileMeshPolicy(withAdoptionModePolicy).manifest.modeCode).toBe(1);
      const shadow: MeshPolicyConfig = {
        ports: [{ path: '/x' }],
        mode: 'shadow',
      };
      expect(compileMeshPolicy(shadow).manifest.modeCode).toBe(2);
    });

    it('manifest.honeypitPresent is true iff any overlay has honeypit=true', () => {
      expect(compileMeshPolicy(withHoneypitPolicy).manifest.honeypitPresent).toBe(true);
      expect(compileMeshPolicy(multiPortWithOverlays).manifest.honeypitPresent).toBe(false);
      expect(compileMeshPolicy(emptyPolicy).manifest.honeypitPresent).toBe(false);
    });

    it('manifest.compiledSize equals bwBytes.length', () => {
      for (const fx of allFixtures) {
        const { bwBytes, manifest } = compileMeshPolicy(fx.policy);
        expect(manifest.compiledSize).toBe(bwBytes.length);
      }
    });

    it('manifest.packedLength <= ceil(nominalSize * 3/4) per bitwise_shrink_4_3', () => {
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        // ceil(n * 3 / 4) in integer arithmetic
        const bound = Math.floor((manifest.nominalSize * 3 + 3) / 4);
        expect(manifest.packedLength).toBeLessThanOrEqual(bound);
      }
    });

    it('manifest.compiledSize stays within ceil(nominalSize*3/4) + framingOverhead', () => {
      // Framing overhead covers BZRO header (10 bytes) + manifest JSON
      // (self-describing field set) + parity sidecar + tail. 512 bytes
      // is a generous cap that every fixture must fit inside.
      const framingOverhead = 512;
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        const shrinkBound = Math.floor((manifest.nominalSize * 3 + 3) / 4);
        expect(manifest.compiledSize).toBeLessThanOrEqual(
          shrinkBound + framingOverhead,
        );
      }
    });

    it('manifest arithmetic: packedLength + parityBytes + tailBytes equals payload section size', () => {
      for (const fx of allFixtures) {
        const { bwBytes, manifest } = compileMeshPolicy(fx.policy);
        // Header = 10 bytes; manifest section follows; payload tail.
        const view = new DataView(
          bwBytes.buffer,
          bwBytes.byteOffset,
          bwBytes.byteLength,
        );
        const manifestLen = view.getUint32(6, true);
        const payloadSectionSize = bwBytes.length - 10 - manifestLen;
        expect(payloadSectionSize).toBe(
          manifest.packedLength + manifest.parityBytes + manifest.tailBytes,
        );
      }
    });

    it('manifest.tailBytes is in [0, 8) for every fixture', () => {
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        expect(manifest.tailBytes).toBeGreaterThanOrEqual(0);
        expect(manifest.tailBytes).toBeLessThan(8);
      }
    });
  });

  // ─── Group 2: round-trip exact ─────────────────────────────────────
  describe('round-trip exact', () => {
    for (const fx of allFixtures) {
      it(`restores '${fx.name}' policy byte-for-byte via compile → load`, () => {
        const { bwBytes } = compileMeshPolicy(fx.policy);
        const { policy: restored } = loadMeshPolicyFromBundle(bwBytes);
        expect(deepEquals(restored, fx.policy)).toBe(true);
      });
    }
  });

  // ─── Group 3: behavioral parity ────────────────────────────────────
  describe('behavioral parity with raw-config runtime', () => {
    const parityRequests: readonly {
      readonly name: string;
      readonly build: () => Request;
    }[] = [
      { name: 'GET /', build: () => new Request('https://x.test/') },
      { name: 'GET /api', build: () => new Request('https://x.test/api') },
      {
        name: 'POST /api',
        build: () => new Request('https://x.test/api', { method: 'POST' }),
      },
      {
        name: 'DELETE /api/v1/admin',
        build: () =>
          new Request('https://x.test/api/v1/admin', { method: 'DELETE' }),
      },
      {
        name: 'OPTIONS /api',
        build: () => new Request('https://x.test/api', { method: 'OPTIONS' }),
      },
      {
        name: 'HEAD /api',
        build: () => new Request('https://x.test/api', { method: 'HEAD' }),
      },
      {
        name: 'GET /api with auth',
        build: () =>
          new Request('https://x.test/api', {
            headers: { authorization: 'Bearer zzz' },
          }),
      },
      {
        name: 'GET /api without auth',
        build: () => new Request('https://x.test/api'),
      },
      {
        name: 'GET /health',
        build: () => new Request('https://x.test/health'),
      },
      {
        name: 'GET /api/admin (overlay-blocked)',
        build: () =>
          new Request('https://x.test/api/admin/reset', {
            headers: { authorization: 'Bearer zzz' },
          }),
      },
    ];

    for (const fx of allFixtures) {
      for (const req of parityRequests) {
        it(`fixture '${fx.name}' ${req.name}`, async () => {
          const { raw, compiled } = await runBoth(fx.policy, req.build());
          assertSameResponse(raw, compiled);
        });
      }
    }
  });

  // ─── Group 4: manifest inspection ──────────────────────────────────
  describe('manifest inspection', () => {
    it('inspectCompiledBundle returns the same manifest as compile', () => {
      for (const fx of allFixtures) {
        const { bwBytes, manifest } = compileMeshPolicy(fx.policy);
        const inspected = inspectCompiledBundle(bwBytes);
        expect(deepEquals(inspected, manifest)).toBe(true);
      }
    });

    it('inspect is available via the consumer module re-export', () => {
      const { bwBytes, manifest } = compileMeshPolicy(multiPortWithOverlays);
      const inspected = inspectCompiledBundleAlt(bwBytes);
      expect(deepEquals(inspected, manifest)).toBe(true);
    });

    it('throws on corrupt magic bytes', () => {
      const { bwBytes } = compileMeshPolicy(singlePortPolicy);
      const corrupt = new Uint8Array(bwBytes);
      corrupt[0] = 0xff;
      let threw = false;
      try {
        inspectCompiledBundle(corrupt);
      } catch (_err) {
        threw = true;
      }
      expect(threw).toBe(true);
    });

    it('throws on corrupt manifest JSON bytes', () => {
      const { bwBytes } = compileMeshPolicy(singlePortPolicy);
      const corrupt = new Uint8Array(bwBytes);
      // Scramble the first byte of the manifest body (JSON should start
      // with '{' = 0x7b; any non-'{' byte breaks the parse).
      corrupt[10] = 0x5a;
      let threw = false;
      try {
        inspectCompiledBundle(corrupt);
      } catch (_err) {
        threw = true;
      }
      expect(threw).toBe(true);
    });

    it('throws on wrong container kind byte', () => {
      const { bwBytes } = compileMeshPolicy(singlePortPolicy);
      const corrupt = new Uint8Array(bwBytes);
      corrupt[5] = 0x09;
      let threw = false;
      try {
        inspectCompiledBundle(corrupt);
      } catch (_err) {
        threw = true;
      }
      expect(threw).toBe(true);
    });
  });

  // ─── Group 5: version validation + node-free surface ───────────────
  describe('version validation and node-free surface', () => {
    function makeUnknownFormatBundle(): Uint8Array {
      // Hand-assemble a bundle whose manifest carries an unknown
      // `format` sentinel. We start from a real compiled bundle to
      // keep the payload parseable, then rewrite the manifest block.
      const { bwBytes } = compileMeshPolicy(singlePortPolicy);
      const view = new DataView(
        bwBytes.buffer,
        bwBytes.byteOffset,
        bwBytes.byteLength,
      );
      const manifestLen = view.getUint32(6, true);
      const manifestBytes = bwBytes.subarray(10, 10 + manifestLen);
      const decoder = new TextDecoder();
      const encoder = new TextEncoder();
      const manifestObj = JSON.parse(decoder.decode(manifestBytes)) as Record<string, unknown>;
      manifestObj.format = 'mesh-policy-v99';
      const rewritten = encoder.encode(JSON.stringify(manifestObj));
      // If lengths differ, repack the container so the reader
      // accepts it as structurally valid and fails only at the version gate.
      const payloadStart = 10 + manifestLen;
      const payloadBytes = bwBytes.subarray(payloadStart);
      const total = 10 + rewritten.length + payloadBytes.length;
      const out = new Uint8Array(total);
      out.set(bwBytes.subarray(0, 6), 0);
      const outView = new DataView(out.buffer, out.byteOffset, out.byteLength);
      outView.setUint32(6, rewritten.length, true);
      out.set(rewritten, 10);
      out.set(payloadBytes, 10 + rewritten.length);
      return out;
    }

    it('throws by default when manifest.format is unknown', () => {
      const bogus = makeUnknownFormatBundle();
      let threw = false;
      try {
        wrapWithMeshPolicyCompiled(okInner, bogus);
      } catch (err) {
        threw = true;
        expect((err as Error).message.includes('mesh-policy-v99')).toBe(true);
      }
      expect(threw).toBe(true);
    });

    it('throws when strictVersion is explicitly true and format is unknown', () => {
      const bogus = makeUnknownFormatBundle();
      let threw = false;
      try {
        wrapWithMeshPolicyCompiled(okInner, bogus, { strictVersion: true });
      } catch (_err) {
        threw = true;
      }
      expect(threw).toBe(true);
    });

    it('falls back to deny-all when strictVersion is false', async () => {
      const bogus = makeUnknownFormatBundle();
      const auditLines: string[] = [];
      const wrapped = wrapWithMeshPolicyCompiled(okInner, bogus, {
        strictVersion: false,
        audit: (m) => auditLines.push(m),
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      // Deny-all → empty ports → 404 for every path.
      expect(res.status).toBe(404);
      expect(auditLines.length).toBe(1);
      expect(auditLines[0]!.includes('unknown-format')).toBe(true);
      expect(auditLines[0]!.includes('mesh-policy-v99')).toBe(true);
    });

    it('content-address fingerprint is a 64-char lowercase hex string', () => {
      for (const fx of allFixtures) {
        const { manifest } = compileMeshPolicy(fx.policy);
        expect(typeof manifest.bundleFingerprint).toBe('string');
        expect(manifest.bundleFingerprint.length).toBe(64);
        expect(/^[0-9a-f]{64}$/.test(manifest.bundleFingerprint)).toBe(true);
      }
    });

    it('fingerprint is deterministic: same input yields same fingerprint', () => {
      const a = compileMeshPolicy(multiPortWithOverlays, {
        timestamp: '2026-04-19T12:00:00.000Z',
      });
      const b = compileMeshPolicy(multiPortWithOverlays, {
        timestamp: '2026-04-19T12:00:00.000Z',
      });
      expect(a.manifest.bundleFingerprint).toBe(b.manifest.bundleFingerprint);
    });

    it('fingerprint distinguishes different policies (changed port path)', () => {
      const a = compileMeshPolicy({
        ports: [{ path: '/api' }],
      }).manifest.bundleFingerprint;
      const b = compileMeshPolicy({
        ports: [{ path: '/other' }],
      }).manifest.bundleFingerprint;
      expect(a === b).toBe(false);
    });

    it('fingerprint distinguishes different timestamps', () => {
      const a = compileMeshPolicy(singlePortPolicy, {
        timestamp: '2026-01-01T00:00:00.000Z',
      }).manifest.bundleFingerprint;
      const b = compileMeshPolicy(singlePortPolicy, {
        timestamp: '2026-02-01T00:00:00.000Z',
      }).manifest.bundleFingerprint;
      expect(a === b).toBe(false);
    });

    it('fingerprintMeshPolicyBundle(bwBytes) matches manifest.bundleFingerprint', () => {
      for (const fx of allFixtures) {
        const { bwBytes, manifest } = compileMeshPolicy(fx.policy);
        const recomputed = fingerprintMeshPolicyBundle(bwBytes);
        expect(recomputed).toBe(manifest.bundleFingerprint);
      }
    });

    it('fingerprintMeshPolicyBundle matches a known SHA-256 vector (empty input)', () => {
      // SHA-256("") per RFC 6234 / FIPS 180-4.
      const empty = new Uint8Array(0);
      expect(fingerprintMeshPolicyBundle(empty)).toBe(
        'e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855',
      );
    });

    it('fingerprintMeshPolicyBundle matches a known SHA-256 vector (ascii abc)', () => {
      // SHA-256("abc") per FIPS 180-4 Appendix B.
      const bytes = new TextEncoder().encode('abc');
      expect(fingerprintMeshPolicyBundle(bytes)).toBe(
        'ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad',
      );
    });

    it('inspectCompiledBundle surfaces the same fingerprint as compile', () => {
      for (const fx of allFixtures) {
        const { bwBytes, manifest } = compileMeshPolicy(fx.policy);
        const inspected = inspectCompiledBundle(bwBytes);
        expect(inspected.bundleFingerprint).toBe(manifest.bundleFingerprint);
      }
    });

    it('production source files have no node: imports, no process., no console., no Buffer.', () => {
      const sources = [
        '../mesh-policy-compile.ts',
        '../mesh-policy-edge-compiled.ts',
      ];
      const forbidden = [
        /from\s+['"]node:/,
        /require\(\s*['"]node:/,
        /\bprocess\./,
        /\bconsole\./,
        /\bBuffer\./,
      ];
      for (const rel of sources) {
        const url = new URL(rel, import.meta.url);
        const path = fileURLToPath(url);
        const source = readFileSync(path, 'utf8');
        for (const pattern of forbidden) {
          const m = source.match(pattern);
          expect(m).toBeNull();
        }
      }
    });
  });
});
